// Valida o hottok da Hotmart e normaliza o evento
const item = $input.item.json;
const headers = item.headers || {};
const body = item.body || {};

const expected = $env.HOTMART_HOTTOK;
const received = headers['x-hotmart-hottok'];
if (expected && received !== expected) {
  throw new Error('Hottok inválido — evento descartado (possível requisição falsa)');
}

const data = body.data || {};
const purchase = data.purchase || {};
const product = data.product || {};

const eventRow = {
  event_id: body.id || null,
  event: body.event || 'UNKNOWN',
  version: body.version || null,
  product_id: product.id ?? null,
  product_name: product.name || null,
  transaction: purchase.transaction || null,
  payload: body,
};

return { json: { eventRow, body } };

// Transforma eventos PURCHASE_* em registro de venda.
// Eventos que não são de compra (ou sem transaction, ex: carrinho abandonado)
// ficam apenas em hotmart_events.
const body = $('Validar e Normalizar').item.json.body;
const event = body.event || '';

const STATUS = {
  PURCHASE_APPROVED: 'APPROVED',
  PURCHASE_COMPLETE: 'COMPLETE',
  PURCHASE_REFUNDED: 'REFUNDED',
  PURCHASE_CHARGEBACK: 'CHARGEBACK',
  PURCHASE_CANCELED: 'CANCELED',
  PURCHASE_BILLET_PRINTED: 'BILLET_PRINTED',
  PURCHASE_EXPIRED: 'EXPIRED',
  PURCHASE_DELAYED: 'DELAYED',
  PURCHASE_PROTEST: 'PROTEST',
};

const data = body.data || {};
const purchase = data.purchase || {};
const product = data.product || {};
const buyer = data.buyer || {};
const origin = purchase.origin || {};

if (!STATUS[event] || !purchase.transaction) {
  return null; // não é venda — encerra este item aqui
}

const toIso = (v) => (v ? new Date(v).toISOString() : undefined);

// Atribuição: sck no padrão meta|CAMPAIGN_ID|ADSET_ID|AD_ID (ou sem o prefixo)
const src = origin.xcod || origin.src || undefined;
const sck = origin.sck || undefined;
let utm_campaign_id, utm_adset_id, utm_ad_id;
if (sck) {
  const parts = String(sck).split('|');
  const p = parts[0].toLowerCase() === 'meta' ? parts.slice(1) : parts;
  utm_campaign_id = p[0] || undefined;
  utm_adset_id = p[1] || undefined;
  utm_ad_id = p[2] || undefined;
}

const isApproval = event === 'PURCHASE_APPROVED' || event === 'PURCHASE_COMPLETE';
const isRefund = event === 'PURCHASE_REFUNDED' || event === 'PURCHASE_CHARGEBACK';

const sale = {
  transaction: purchase.transaction,
  product_id: product.id,
  product_name: product.name,
  buyer_email: buyer.email,
  buyer_name: buyer.name,
  status: STATUS[event],
  price: purchase.price?.value,
  currency: purchase.price?.currency_value,
  payment_type: purchase.payment?.type,
  src,
  sck,
  utm_campaign_id,
  utm_adset_id,
  utm_ad_id,
  ordered_at: toIso(purchase.order_date),
  approved_at: isApproval ? toIso(purchase.approved_date || body.creation_date) : undefined,
  refunded_at: isRefund ? toIso(body.creation_date) : undefined,
};

// Remove campos vazios para o upsert não sobrescrever dados já gravados com null
for (const k of Object.keys(sale)) {
  if (sale[k] === undefined || sale[k] === null) delete sale[k];
}

return { json: { sale } };
